section.programlisting:
1 #ifndef HDEF_PROFILER
2 #define HDEF_PROFILER
3 
4 #include <chrono>
5 #include <string>
6 #include <unordered_map>
7 #include <iostream>
8 #include <sstream>
9 
10 namespace Mochi::Debug
11 {
12     class FrameProfiler
13     {
14     public:
15         void BeginSection(const std::string &name)
16         {
17             mSections[name].start = std::chrono::high_resolution_clock::now();
18         }
19 
20         void EndSection(const std::string &name)
21         {
22             auto end = std::chrono::high_resolution_clock::now();
23             auto &s = mSections[name];
24             s.accum += std::chrono::duration<double, std::milli>(end - s.start).count();
25         }
26 
27         void NewFrame()
28         {
29             for (auto &[_, s] : mSections)
30                 s.accum = 0.0;
31         }
32 
33         std::string Report() const
34         {
35             double total = 0.0;
36             for (auto &[name, s] : mSections)
37                 total += s.accum;
38 
39             std::stringstream ss;
40             ss << "START OF FRAME REPORT\n";
41             ss << "Frame " << total << " ms\n";
42             for (auto &[name, s] : mSections)
43                 ss << name << ": " << s.accum << "ms\n";
44             ss << "END OF FRAME REPORT\n";
45             return ss.str();
46         }
47 
48     private:
49         struct Section
50         {
51             std::chrono::high_resolution_clock::time_point start;
52             double accum = 0.0;
53         };
54         std::unordered_map<std::string, Section> mSections;
55     };
56 }
57 
58 #endif
